        token_doc = {
            'token': token,
            'expires_at': datetime.utcnow() + timedelta(minutes=expires_in),
            'user_id': user_id
        }
        self.users_collection.update_one({'user_id': user_id}, {'$set': token_doc}, upsert=True)

